      "path": "src/modules/tasks/service.js",
      "content": "const tasks = [];
module.exports = {
  createTask: (projectId, taskData) => {
    const task = { id: randomUUID(), projectId, status: 'todo', ...taskData };
    tasks.push(task);
    return task;
  },
  updateTaskStatus: (taskId, newStatus) => {
    const task = tasks.find(t => t.id === taskId);
    if (!['todo', 'done'].includes(newStatus)) throw new Error('Invalid status');
    task.status = newStatus;
  },
  getTasksByStatus: (projectId, status) => tasks.filter(t => t.projectId === projectId && t.status === status)
};
